const express = require('express');
const helmet = require('helmet');
const cors = require('cors');
const rateLimit = require('express-rate-limit');
const { body, query, validationResult } = require('express-validator');
const jwt = require('jsonwebtoken');
const { v4: uuidv4 } = require('uuid');
const pino = require('pino');
require('dotenv').config();

const app = express();
const logger = pino({
  level: process.env.LOG_LEVEL || 'info',
  redact: {
    paths: ['req.headers.authorization', 'req.headers.cookie'],
    remove: true
  }
});

// ============================================================================
// Security Middleware
// ============================================================================

// 1. Security Headers
app.use(helmet({
  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"],
      scriptSrc: ["'self'"],
      styleSrc: ["'self'", "'unsafe-inline'"],
    }
  },
  hsts: { maxAge: 31536000, includeSubDomains: true }
}));

// 2. CORS Configuration
app.use(cors({
  origin: (process.env.ALLOWED_ORIGINS || 'http://localhost:3000').split(','),
  credentials: true,
  methods: ['GET', 'POST', 'OPTIONS'],
  allowedHeaders: ['Content-Type', 'Authorization'],
  maxAge: 86400
}));

// 3. Rate Limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // 100 requests per windowMs
  message: 'Too many requests, please try again later',
  standardHeaders: true,
  legacyHeaders: false
});

const authLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 5, // Stricter limit for auth
  skipSuccessfulRequests: true
});

app.use(limiter);

// 4. Request Body Parsing with Size Limits
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ limit: '10kb', extended: false }));

// 5. Request ID Tracking
app.use((req, res, next) => {
  req.id = req.headers['x-request-id'] || uuidv4();
  res.set('X-Request-ID', req.id);
  next();
});

// ============================================================================
// Authentication Middleware
// ============================================================================

const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) {
    logger.warn({ requestId: req.id, msg: 'Missing auth token' });
    return res.status(401).json({
      error: 'Authentication required',
      requestId: req.id
    });
  }

  jwt.verify(token, process.env.JWT_SECRET || 'dev-secret', (err, user) => {
    if (err) {
      logger.warn({ requestId: req.id, msg: 'Invalid token', error: err.message });
      return res.status(403).json({
        error: 'Invalid or expired token',
        requestId: req.id
      });
    }
    req.user = user;
    next();
  });
};

// ============================================================================
// Routes
// ============================================================================

// Health check endpoint - public, no sensitive data
app.get('/health', (req, res) => {
  res.json({
    status: 'ok',
    timestamp: new Date().toISOString()
  });
});

// Users endpoint - requires authentication
app.get('/users',
  authenticateToken,
  [
    query('page').optional().isInt({ min: 1 }).toInt(),
    query('limit').optional().isInt({ min: 1, max: 100 }).toInt()
  ],
  (req, res, next) => {
    // Validate input
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      logger.warn({
        requestId: req.id,
        errors: errors.array(),
        msg: 'Validation error'
      });
      return res.status(400).json({
        error: 'Invalid request parameters',
        details: errors.array(),
        requestId: req.id
      });
    }
    next();
  },
  (req, res) => {
    try {
      const page = req.query.page || 1;
      const limit = req.query.limit || 10;

      // Mock data - in real app, query from database
      const users = [
        { id: 1, name: 'Alice' },
        { id: 2, name: 'Bob' }
      ];

      logger.info({
        requestId: req.id,
        userId: req.user.id,
        page,
        limit,
        msg: 'Users fetched'
      });

      res.json({
        data: users,
        page,
        limit,
        total: users.length,
        requestId: req.id
      });
    } catch (err) {
      next(err);
    }
  }
);

// Login endpoint (example) - demonstrates JWT flow
app.post('/login',
  authLimiter,
  [
    body('username').trim().isLength({ min: 1, max: 50 }).escape(),
    body('password').isLength({ min: 1 })
  ],
  (req, res, next) => {
    // Validate input
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      logger.warn({
        requestId: req.id,
        errors: errors.array(),
        msg: 'Login validation error'
      });
      return res.status(400).json({
        error: 'Invalid credentials format',
        requestId: req.id
      });
    }
    next();
  },
  (req, res) => {
    try {
      const { username, password } = req.body;

      // Mock authentication - in real app, validate against database
      if (username === 'demo' && password === 'demo') {
        const token = jwt.sign(
          { id: 1, username },
          process.env.JWT_SECRET || 'dev-secret',
          { expiresIn: '1h' }
        );

        logger.info({
          requestId: req.id,
          username,
          msg: 'User logged in successfully'
        });

        res.json({
          token,
          expiresIn: 3600,
          requestId: req.id
        });
      } else {
        logger.warn({
          requestId: req.id,
          username,
          msg: 'Failed login attempt'
        });
        res.status(401).json({
          error: 'Invalid credentials',
          requestId: req.id
        });
      }
    } catch (err) {
      next(err);
    }
  }
);

// ============================================================================
// 404 Handler
// ============================================================================

app.use((req, res) => {
  res.status(404).json({
    error: 'Not found',
    path: req.path,
    requestId: req.id
  });
});

// ============================================================================
// Global Error Handler (MUST be last)
// ============================================================================

app.use((err, req, res, next) => {
  const isDevelopment = process.env.NODE_ENV === 'development';
  const statusCode = err.statusCode || err.status || 500;

  // Log error with full context
  logger.error({
    requestId: req.id,
    message: err.message,
    stack: err.stack,
    path: req.path,
    method: req.method,
    statusCode,
    userId: req.user?.id
  });

  // Response to client - don't expose internal details in production
  const response = {
    error: isDevelopment ? err.message : 'Internal server error',
    requestId: req.id
  };

  if (isDevelopment && err.stack) {
    response.stack = err.stack;
  }

  res.status(statusCode).json(response);
});

// ============================================================================
// Server Startup
// ============================================================================

const PORT = process.env.PORT || 3000;
const NODE_ENV = process.env.NODE_ENV || 'development';

// Validate required environment variables in production
if (NODE_ENV === 'production') {
  if (!process.env.JWT_SECRET) {
    logger.error('JWT_SECRET not set in production');
    process.exit(1);
  }
  if (!process.env.ALLOWED_ORIGINS) {
    logger.error('ALLOWED_ORIGINS not set in production');
    process.exit(1);
  }
}

const server = app.listen(PORT, () => {
  logger.info(`Server started in ${NODE_ENV} mode`);
});

// Graceful shutdown
process.on('SIGTERM', () => {
  logger.info('SIGTERM received, shutting down gracefully');
  server.close(() => {
    logger.info('Server closed');
    process.exit(0);
  });
});

process.on('SIGINT', () => {
  logger.info('SIGINT received, shutting down gracefully');
  server.close(() => {
    logger.info('Server closed');
    process.exit(0);
  });
});

// Catch unhandled promise rejections
process.on('unhandledRejection', (reason, promise) => {
  logger.error({
    error: 'Unhandled Rejection',
    reason,
    promise
  });
  process.exit(1);
});

module.exports = app;

