require('dotenv').config();

const express = require('express');
const compression = require('compression');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const cors = require('cors');
const { query, validationResult } = require('express-validator');
const uuid = require('uuid');
const winston = require('winston');
const promClient = require('prom-client');

// ============================================================================
// CONFIGURATION
// ============================================================================

const PORT = process.env.PORT || 3000;
const NODE_ENV = process.env.NODE_ENV || 'development';
const LOG_LEVEL = process.env.LOG_LEVEL || 'info';
const CORS_ORIGIN = process.env.CORS_ORIGIN || 'http://localhost:3000';
const REQUEST_TIMEOUT = parseInt(process.env.REQUEST_TIMEOUT || '30000');
const SHUTDOWN_TIMEOUT = parseInt(process.env.SHUTDOWN_TIMEOUT || '30000');

// ============================================================================
// LOGGING SETUP
// ============================================================================

const logger = winston.createLogger({
  level: LOG_LEVEL,
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.errors({ stack: true }),
    winston.format.json()
  ),
  defaultMeta: { service: 'api-server' },
  transports: [
    new winston.transports.Console({
      format: NODE_ENV === 'development'
        ? winston.format.combine(
            winston.format.colorize(),
            winston.format.simple()
          )
        : winston.format.json(),
    }),
  ],
});

// ============================================================================
// PROMETHEUS METRICS
// ============================================================================

const httpRequestDuration = new promClient.Histogram({
  name: 'http_request_duration_ms',
  help: 'Duration of HTTP requests in ms',
  labelNames: ['method', 'route', 'status_code'],
  buckets: [0.1, 5, 15, 50, 100, 500],
});

const httpRequestTotal = new promClient.Counter({
  name: 'http_requests_total',
  help: 'Total number of HTTP requests',
  labelNames: ['method', 'route', 'status_code'],
});

const httpErrorsTotal = new promClient.Counter({
  name: 'http_errors_total',
  help: 'Total number of HTTP errors',
  labelNames: ['method', 'route', 'error_type'],
});

// ============================================================================
// EXPRESS APP SETUP
// ============================================================================

const app = express();

// Request size limiting
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ limit: '10kb', extended: true }));

// Compression
app.use(compression({
  threshold: 1024,
  level: 6,
}));

// Security headers
app.use(helmet());

// CORS
const corsOptions = {
  origin: CORS_ORIGIN,
  credentials: true,
  methods: ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS'],
  optionsSuccessStatus: 200,
  maxAge: 86400,
};
app.use(cors(corsOptions));

// Rate limiting
const limiter = rateLimit({
  windowMs: parseInt(process.env.RATE_LIMIT_WINDOW || '15') * 60 * 1000,
  max: parseInt(process.env.RATE_LIMIT_MAX_REQUESTS || '100'),
  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true,
  legacyHeaders: false,
});

app.use('/api/', limiter);

// ============================================================================
// MIDDLEWARE: REQUEST CORRELATION & LOGGING
// ============================================================================

app.use((req, res, next) => {
  const requestId = req.get('X-Request-ID') || uuid.v4();
  res.setHeader('X-Request-ID', requestId);
  req.id = requestId;

  const start = Date.now();

  res.on('finish', () => {
    const duration = Date.now() - start;

    // Record metrics
    const route = req.route?.path || req.path;
    httpRequestDuration
      .labels(req.method, route, res.statusCode)
      .observe(duration);

    httpRequestTotal
      .labels(req.method, route, res.statusCode)
      .inc();

    // Log request
    logger.info('HTTP request completed', {
      requestId,
      method: req.method,
      path: req.path,
      statusCode: res.statusCode,
      duration,
      ip: req.ip,
    });
  });

  next();
});

// ============================================================================
// UTILITY: RESPONSE FORMATTER
// ============================================================================

const sendResponse = (res, data, statusCode = 200, message = 'Success') => {
  res.status(statusCode).json({
    success: statusCode < 400,
    message,
    data,
    timestamp: new Date().toISOString(),
    requestId: res.getHeader('X-Request-ID'),
  });
};

// ============================================================================
// ROUTES: HEALTH CHECK
// ============================================================================

// Liveness check (is server running?)
app.get('/healthz', (req, res) => {
  sendResponse(res, {
    status: 'alive',
    uptime: process.uptime(),
    memory: process.memoryUsage(),
  });
});

// Readiness check (ready to accept traffic?)
app.get('/ready', (req, res) => {
  try {
    // Check dependencies would go here
    // await checkDatabase();
    // await checkCache();

    sendResponse(res, {
      status: 'ready',
      dependencies: {
        database: 'ok',
        cache: 'ok',
      },
    });
  } catch (error) {
    logger.error('Readiness check failed', {
      requestId: req.id,
      error: error.message,
    });

    httpErrorsTotal
      .labels('GET', '/ready', 'dependency_error')
      .inc();

    sendResponse(
      res,
      { status: 'not-ready', error: error.message },
      503,
      'Service Not Ready'
    );
  }
});

// ============================================================================
// ROUTES: USERS
// ============================================================================

const validateGetUsers = [
  query('page')
    .optional()
    .isInt({ min: 1 })
    .toInt(),
  query('limit')
    .optional()
    .isInt({ min: 1, max: 100 })
    .toInt(),
  (req, res, next) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      logger.warn('Validation error', {
        requestId: req.id,
        errors: errors.array(),
      });

      httpErrorsTotal
        .labels('GET', '/api/users', 'validation_error')
        .inc();

      return sendResponse(
        res,
        { errors: errors.array() },
        400,
        'Validation failed'
      );
    }
    next();
  },
];

app.get('/api/users', validateGetUsers, (req, res) => {
  try {
    const page = req.query.page || 1;
    const limit = req.query.limit || 10;

    // Mock data
    const allUsers = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    const startIndex = (page - 1) * limit;
    const paginatedUsers = allUsers.slice(startIndex, startIndex + limit);

    sendResponse(
      res,
      {
        items: paginatedUsers,
        pagination: {
          page,
          limit,
          total: allUsers.length,
          pages: Math.ceil(allUsers.length / limit),
        },
      },
      200,
      'Users retrieved successfully'
    );
  } catch (error) {
    logger.error('Error fetching users', {
      requestId: req.id,
      error: error.message,
      stack: error.stack,
    });

    httpErrorsTotal
      .labels('GET', '/api/users', 'server_error')
      .inc();

    sendResponse(
      res,
      { error: NODE_ENV === 'production' ? 'Internal Server Error' : error.message },
      500,
      'Failed to retrieve users'
    );
  }
});

// ============================================================================
// ROUTES: METRICS
// ============================================================================

app.get('/metrics', (req, res) => {
  res.set('Content-Type', promClient.register.contentType);
  res.end(promClient.register.metrics());
});

// ============================================================================
// ERROR HANDLING
// ============================================================================

// 404 handler
app.use((req, res) => {
  sendResponse(
    res,
    { path: req.path, method: req.method },
    404,
    'Not Found'
  );
});

// Global error handler (must be last)
app.use((err, req, res, next) => {
  const statusCode = err.statusCode || 500;
  const message = err.message || 'Internal Server Error';

  logger.error('Unhandled error', {
    requestId: req.id,
    statusCode,
    message,
    stack: err.stack,
  });

  httpErrorsTotal
    .labels(req.method, req.path, err.code || 'unknown')
    .inc();

  const errorMessage = NODE_ENV === 'production'
    ? 'Internal Server Error'
    : message;

  sendResponse(
    res,
    { error: errorMessage },
    statusCode,
    'An error occurred'
  );
});

// ============================================================================
// SERVER STARTUP
// ============================================================================

const server = app.listen(PORT, () => {
  logger.info(`Server started`, {
    port: PORT,
    environment: NODE_ENV,
    requestTimeout: REQUEST_TIMEOUT,
  });
});

// Server timeouts
server.setTimeout(REQUEST_TIMEOUT);
server.keepAliveTimeout = 65000;

// ============================================================================
// GRACEFUL SHUTDOWN
// ============================================================================

const gracefulShutdown = (signal) => {
  logger.info(`Graceful shutdown initiated by ${signal}`);

  const shutdownTimer = setTimeout(() => {
    logger.error('Forced shutdown due to timeout');
    process.exit(1);
  }, SHUTDOWN_TIMEOUT);

  server.close(() => {
    logger.info('HTTP server closed');
    clearTimeout(shutdownTimer);
    process.exit(0);
  });

  // Stop accepting new connections
  server.closeAllConnections?.();
};

process.on('SIGTERM', () => gracefulShutdown('SIGTERM'));
process.on('SIGINT', () => gracefulShutdown('SIGINT'));

// ============================================================================
// UNHANDLED ERRORS
// ============================================================================

process.on('uncaughtException', (error) => {
  logger.error('Uncaught exception', {
    error: error.message,
    stack: error.stack,
  });
  process.exit(1);
});

process.on('unhandledRejection', (reason, promise) => {
  logger.error('Unhandled rejection', {
    reason,
    promise: promise.toString(),
  });
});

// ============================================================================

module.exports = app;

# Express.js Security Remediation Guide

## Quick Reference: How to Fix Each Issue

---

## CRITICAL: Sensitive Data Exposure

**Problem**: User emails exposed to unauthenticated requests
```javascript
// VULNERABLE
app.get('/users', (req, res) => {
  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },  // Exposed!
    { id: 2, name: 'Bob', email: 'bob@example.com' }
  ]);
});
```

**Solution 1: Add Authentication**
```javascript
app.get('/users', authenticateToken, (req, res) => {
  // Only authenticated users can access
  res.json([
    { id: 1, name: 'Alice' },  // Email removed
    { id: 2, name: 'Bob' }
  ]);
});
```

**Solution 2: Role-Based Access (Better)**
```javascript
app.get('/users', authenticateToken, authorize(['admin']), (req, res) => {
  // Only admins can access user list
  res.json([...]);
});

// Standard users see only their own profile
app.get('/users/me', authenticateToken, (req, res) => {
  res.json({ id: req.user.id, name: req.user.name });
});
```

