## HIGH: No Authentication

**Problem**: Any user can access any endpoint
```javascript
// VULNERABLE
app.get('/users', (req, res) => {
  res.json(allUsers);  // No auth check!
});
```

**Solution: JWT Authentication**

**Step 1: Install JWT library**
```bash
npm install jsonwebtoken
```

**Step 2: Create auth middleware**
```javascript
const jwt = require('jsonwebtoken');

const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];  // "Bearer TOKEN"

  if (!token) {
    return res.status(401).json({ error: 'Access token required' });
  }

  jwt.verify(token, process.env.JWT_SECRET, (err, user) => {
    if (err) {
      return res.status(403).json({ error: 'Invalid or expired token' });
    }
    req.user = user;  // Attach user to request
    next();
  });
};
```

**Step 3: Apply to protected routes**
```javascript
app.get('/users', authenticateToken, (req, res) => {
  res.json([...]);  // Now only authenticated users see this
});
```

**Step 4: Create login endpoint**
```javascript
app.post('/login', (req, res) => {
  const { username, password } = req.body;

  // Verify credentials (check database in real app)
  if (validCredentials(username, password)) {
    const token = jwt.sign(
      { id: user.id, username: user.username },
      process.env.JWT_SECRET,
      { expiresIn: '1h' }
    );

    res.json({ token });
  } else {
    res.status(401).json({ error: 'Invalid credentials' });
  }
});
```

