## HIGH: No Input Validation

**Problem**: Accept any input; vulnerable to injection, crashes
```javascript
// VULNERABLE
app.get('/users', (req, res) => {
  const page = req.query.page;  // Could be anything!
  const data = users.slice(page * 10);
  res.json(data);
});
```

**Solution**:
```javascript
const { query, body, validationResult } = require('express-validator');

app.get('/users',
  // Define validation rules
  query('page')
    .optional()
    .isInt({ min: 1 })           // Must be positive integer
    .toInt(),                      // Convert to number
  query('limit')
    .optional()
    .isInt({ min: 1, max: 100 })  // Max 100 items per page
    .toInt(),
  query('search')
    .optional()
    .trim()
    .escape()                      // Sanitize HTML characters
    .isLength({ max: 100 }),       // Limit length

  // Check for validation errors
  (req, res, next) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({
        error: 'Invalid request parameters',
        details: errors.array()
      });
    }
    next();
  },

  // Handler now receives validated data
  (req, res) => {
    const page = req.query.page || 1;
    const limit = req.query.limit || 10;
    const search = req.query.search || '';

    const results = users
      .filter(u => !search || u.name.includes(search))
      .slice((page - 1) * limit, page * limit);

    res.json(results);
  }
);
```

**For POST body validation**:
```javascript
app.post('/users',
  authenticateToken,
  [
    body('name')
      .trim()
      .escape()
      .isLength({ min: 1, max: 100 })
      .withMessage('Name must be 1-100 characters'),

    body('email')
      .trim()
      .isEmail()
      .normalizeEmail()
      .withMessage('Invalid email address'),

    body('password')
      .isLength({ min: 8 })
      .matches(/[A-Z]/)
      .matches(/[0-9]/)
      .withMessage('Password must be 8+ chars with uppercase and number')
  ],
  (req, res, next) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }
    next();
  },
  (req, res) => {
    // Safe to use req.body now
    createUser(req.body);
    res.status(201).json({ success: true });
  }
);
```

