## HIGH: Sensitive Information in Logs

**Problem**: Expose timing, port, or secrets in logs
```javascript
// VULNERABLE
app.listen(3000, () => {
  console.log('Server running on port 3000');  // Exposed port!
});
```

**Solution**:
```javascript
const pino = require('pino');
require('dotenv').config();

const logger = pino({
  level: process.env.LOG_LEVEL || 'info',

  // Automatically redact sensitive fields
  redact: {
    paths: [
      'req.headers.authorization',
      'req.headers.cookie',
      'req.body.password',
      'res.headers["set-cookie"]'
    ],
    remove: true  // Remove redacted fields from logs
  }
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  logger.info('Server started');  // Generic log
});

// Use structured logging throughout app
logger.info({
  msg: 'User login',
  userId: user.id,
  timestamp: new Date().toISOString()
});

logger.error({
  msg: 'Database error',
  error: err.message,
  // Password automatically redacted if included
});
```

