## MEDIUM: No Rate Limiting

**Problem**: Vulnerable to DoS, brute force attacks
```javascript
// VULNERABLE - unlimited requests allowed
app.post('/login', (req, res) => {
  validateCredentials(req.body);
  res.json({ token });
});
```

**Solution**:
```javascript
const rateLimit = require('express-rate-limit');

// General rate limiter
const generalLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,  // 15 minutes
  max: 100,                   // 100 requests per window
  message: 'Too many requests, please try again later',
  standardHeaders: true,      // Return rate info in headers
  legacyHeaders: false,       // Disable X-RateLimit-* headers
  skip: (req, res) => req.user?.isAdmin  // Skip for admins
});

// Strict limiter for auth endpoints
const authLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 5,                      // Only 5 login attempts
  skipSuccessfulRequests: true // Don't count successful logins
});

// Apply limiters
app.use(generalLimiter);  // Apply to all routes

app.post('/login', authLimiter, (req, res) => {
  // Protected from brute force
});

app.post('/forgot-password', authLimiter, (req, res) => {
  // Protected from enumeration attacks
});
```

