## MEDIUM: No Request ID Tracking

**Problem**: Cannot trace requests; poor debugging
```javascript
// VULNERABLE - no request tracking
app.get('/users', (req, res) => {
  logger.info('Users requested');  // Which request?
  res.json([...]);
});
```

**Solution**:
```javascript
const { v4: uuidv4 } = require('uuid');

app.use((req, res, next) => {
  // Use provided ID or generate new one
  req.id = req.headers['x-request-id'] || uuidv4();

  // Return ID to client
  res.set('X-Request-ID', req.id);

  next();
});

// Use in logging
app.get('/users', (req, res) => {
  logger.info({
    msg: 'Users requested',
    requestId: req.id,           // Traceable!
    userId: req.user?.id
  });
  res.json([...]);
});

// Use in responses
app.use((err, req, res, next) => {
  res.status(500).json({
    error: 'Internal server error',
    requestId: req.id  // Client can report this for support
  });
});
```

